import{_ as p,C as d,o as t,c,a3 as n,b as l,w as e,a as i,E as r,a4 as o}from"./chunks/framework.C49Ar5GK.js";const P=JSON.parse('{"title":"优化方法论：先守住语义，再缩短关键路径","description":"用固定 workload、阶段分解、时间/显存/staleness 三本账和 A/B guardrail 系统优化 veRL 训练与推理","frontmatter":{"title":"优化方法论：先守住语义，再缩短关键路径","description":"用固定 workload、阶段分解、时间/显存/staleness 三本账和 A/B guardrail 系统优化 veRL 训练与推理","lesson":{"stage":"05 · 改造","order":21,"time":"55–80 分钟","level":"高级实战","question":"怎样提高吞吐或降低显存，同时证明没有偷偷改变训练算法与样本分布？"}},"headers":[],"relativePath":"customization/optimization-playbook.md","filePath":"customization/optimization-playbook.md","lastUpdated":null}'),h={name:"customization/optimization-playbook.md"};function u(b,a,m,g,_,f){const s=d("Mermaid");return t(),c("div",null,[a[2]||(a[2]=n(`<h1 id="优化方法论-先守住语义-再缩短关键路径" tabindex="-1">优化方法论：先守住语义，再缩短关键路径 <a class="header-anchor" href="#优化方法论-先守住语义-再缩短关键路径" aria-label="Permalink to &quot;优化方法论：先守住语义，再缩短关键路径&quot;">​</a></h1><p>veRL 优化最容易犯的错误，是把系统变快与实验变了混为一谈。减小 response length、降低 rollout.n、丢弃慢样本都可能让 step 更快，也同时改变任务、优势统计或数据分布。</p><p>真正的优化结论必须同时回答：快在哪里、为什么快、正确性是否保留、代价转移到哪里。</p><h2 id="先用人话-你在平衡三本账" tabindex="-1">先用人话：你在平衡三本账 <a class="header-anchor" href="#先用人话-你在平衡三本账" aria-label="Permalink to &quot;先用人话：你在平衡三本账&quot;">​</a></h2><table tabindex="0"><thead><tr><th>账本</th><th>典型量</th><th>欠账的表现</th></tr></thead><tbody><tr><td>时间</td><td>step time、tokens/s、p95 长尾</td><td>GPU 等待、生成/通信拖慢</td></tr><tr><td>显存</td><td>weights、optimizer、activation、KV cache</td><td>OOM、batch 被迫过小</td></tr><tr><td>新鲜度/质量</td><td>weight version、staleness、reward/length/KL</td><td>异步更快但样本更旧、语义漂移</td></tr></tbody></table><p>把一项成本搬走，常会增加另一本账：offload 省显存却增加 PCIe；更深异步提高利用率却增加 staleness；TP 能放下模型却减少 replica 数并增加通信。</p><h2 id="_0-先写不允许退化的-guardrail" tabindex="-1">0. 先写不允许退化的 guardrail <a class="header-anchor" href="#_0-先写不允许退化的-guardrail" aria-label="Permalink to &quot;0. 先写不允许退化的 guardrail&quot;">​</a></h2><p>优化前固定：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>commit + dirty diff</span></span>
<span class="line"><span>resolved config</span></span>
<span class="line"><span>模型/checkpoint + dtype</span></span>
<span class="line"><span>固定数据切片、seed、长度分布</span></span>
<span class="line"><span>节点/GPU/网络与集群占用</span></span>
<span class="line"><span>预热区间和测量 step</span></span>
<span class="line"><span>primary metric：有效 response tokens/s 或 time-to-train-N-tokens</span></span>
<span class="line"><span>quality guardrails：reward/val、长度、KL、entropy、clipfrac</span></span>
<span class="line"><span>algorithm guardrails：组完整率、drop rate、staleness、非零 advantage 比例</span></span></code></pre></div><p>只报告 samples/s 容易被短回答“优化”；只报告 GPU utilization 无法说明有效工作；只报告 reward 又可能漏掉吞吐退化。</p><h2 id="_1-把一步拆成关键路径" tabindex="-1">1. 把一步拆成关键路径 <a class="header-anchor" href="#_1-把一步拆成关键路径" aria-label="Permalink to &quot;1. 把一步拆成关键路径&quot;">​</a></h2>`,11)),(t(),l(o,null,{default:e(()=>[r(s,{id:"mermaid-78",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20D%5Bdata%5D%20--%3E%20G%5Brollout%5D%0A%20%20%20%20G%20--%3E%20R%5Breward%5D%0A%20%20%20%20R%20--%3E%20O%5Bold%2Fref%2Fvalue%5D%0A%20%20%20%20O%20--%3E%20A%5Badvantage%5D%0A%20%20%20%20A%20--%3E%20U%5Bactor%2Fcritic%20update%5D%0A%20%20%20%20U%20--%3E%20S%5Bweight%20sync%5D%0A%20%20%20%20S%20--%3E%20G%0A"})]),fallback:e(()=>[...a[0]||(a[0]=[i(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=n('<p>V1 已记录 <code>gen</code>、<code>reward</code>、<code>old_log_prob</code>、<code>ref</code>、<code>values</code>、<code>adv</code>、<code>update_critic</code>、<code>update_actor</code> 等计时。先用多步中位数/p95 确定最大段，再分解该段。</p><p>判断规则：优化非关键路径的 2 倍加速，整体可能几乎不变；异步模式还要看并行重叠后的关键路径，不能简单相加阶段时间。</p><h2 id="_2-rollout-慢-区分-prefill、decode、排队与最后一条长尾" tabindex="-1">2. Rollout 慢：区分 prefill、decode、排队与最后一条长尾 <a class="header-anchor" href="#_2-rollout-慢-区分-prefill、decode、排队与最后一条长尾" aria-label="Permalink to &quot;2. Rollout 慢：区分 prefill、decode、排队与最后一条长尾&quot;">​</a></h2><h3 id="先收证据" tabindex="-1">先收证据 <a class="header-anchor" href="#先收证据" aria-label="Permalink to &quot;先收证据&quot;">​</a></h3><ul><li>prompt/response token 分布而非平均长度；</li><li>request arrival/running/waiting、TTFT、inter-token latency；</li><li>KV cache utilization、batch token 数、每 replica 吞吐；</li><li>最后完成的 prompt/group 是否显著更长；</li><li>TP、DP/replica 数与通信占比。</li></ul><h3 id="常见旋钮与代价" tabindex="-1">常见旋钮与代价 <a class="header-anchor" href="#常见旋钮与代价" aria-label="Permalink to &quot;常见旋钮与代价&quot;">​</a></h3><table tabindex="0"><thead><tr><th>旋钮</th><th>可能收益</th><th>必须监控的代价</th></tr></thead><tbody><tr><td>增加 rollout replicas / 减小 TP</td><td>更多并发</td><td>单 replica 是否还能放下模型、权重同步量</td></tr><tr><td>增大 KV cache budget</td><td>更大 batch</td><td>与共置训练显存冲突</td></tr><tr><td>chunked prefill</td><td>减少长 prompt 阻塞 decode</td><td>调度/kernels、版本兼容</td></tr><tr><td>prefix caching</td><td>共享前缀少重复计算</td><td>命中率、cache 占用与失效</td></tr><tr><td>dynamic batching/token budget</td><td>减少 padding、提高占用</td><td>长尾、公平性、峰值显存</td></tr><tr><td>调整 <code>n</code> / 长度</td><td>生成量减少</td><td>直接改变 GRPO 统计或任务，不是纯优化</td></tr></tbody></table><p><a href="https://arxiv.org/abs/2309.06180" target="_blank" rel="noreferrer">PagedAttention 论文</a>解释 KV cache 分页为何提高批处理容量；具体 vLLM/SGLang 行为要以你锁定的后端版本为准。</p><h2 id="_3-actor-critic-慢或-oom-先确定内存所有者" tabindex="-1">3. Actor/Critic 慢或 OOM：先确定内存所有者 <a class="header-anchor" href="#_3-actor-critic-慢或-oom-先确定内存所有者" aria-label="Permalink to &quot;3. Actor/Critic 慢或 OOM：先确定内存所有者&quot;">​</a></h2><p>训练显存大致由 weights、gradients、optimizer states、activations、临时 buffer 和通信 bucket 构成。不要拿 rollout 的 <code>gpu_memory_utilization</code> 修 actor backward OOM。</p><p>可按顺序验证：</p><ol><li><code>use_remove_padding</code> / dynamic token batch 是否减少无效 token；</li><li>micro batch 或 <code>ppo_max_token_len_per_gpu</code> 是否控制单次峰值；</li><li>gradient checkpointing 用计算换 activation；</li><li>FSDP/TP/SP/CP 等并行是否与序列/模型瓶颈匹配；</li><li>parameter/optimizer offload 是否值得通信代价；</li><li>fused kernel/compile 是否在当前 shape 与后端稳定；</li><li>mini-batch/ppo epochs 改动是否改变优化算法，而不只是切分。</li></ol><p>比较时使用<strong>有效训练 token/s</strong>，同时看 MFU、peak allocated/reserved 和 step 内峰值阶段。micro batch 变小能运行但可能让吞吐下降；dynamic batch 能提高利用率但需验证全局 loss 分母一致。</p><h2 id="_4-权重同步慢-它连接两种模型表示" tabindex="-1">4. 权重同步慢：它连接两种模型表示 <a class="header-anchor" href="#_4-权重同步慢-它连接两种模型表示" aria-label="Permalink to &quot;4. 权重同步慢：它连接两种模型表示&quot;">​</a></h2><p>训练引擎可能以 FSDP/Megatron 分片保存权重，推理引擎以另一种 TP/replica 布局消费。同步成本包含 gather/reshard、序列化/传输、server wake/sleep 和版本切换。</p><p>检查：</p><ul><li><code>update_weights</code> 在整体关键路径占比；</li><li>bucket 大小与峰值显存/链路带宽；</li><li>每个 rollout replica 是否重复接收；</li><li>同步频率与每次训练工作量；</li><li>新版本何时真正可服务，旧请求怎样结束。</li></ul><p>降低同步频率可能提高吞吐，却会增加样本 staleness，属于算法-系统联合权衡。必须报告 trajectory version span、drop/correction 指标与质量 guardrail。</p><h2 id="_5-reward-tq-data-慢-cpu-与外部服务也在关键路径上" tabindex="-1">5. Reward/TQ/Data 慢：CPU 与外部服务也在关键路径上 <a class="header-anchor" href="#_5-reward-tq-data-慢-cpu-与外部服务也在关键路径上" aria-label="Permalink to &quot;5. Reward/TQ/Data 慢：CPU 与外部服务也在关键路径上&quot;">​</a></h2><h3 id="reward" tabindex="-1">Reward <a class="header-anchor" href="#reward" aria-label="Permalink to &quot;Reward&quot;">​</a></h3><p>测单调用 p50/p95/p99、并发、超时率和重试。增加 worker 只在下游服务和 CPU 还有容量时有效。规则 reward 可向量化/批处理；沙箱/GenRM 需要限流与失败分数策略。</p><h3 id="transferqueue-replaybuffer" tabindex="-1">TransferQueue/ReplayBuffer <a class="header-anchor" href="#transferqueue-replaybuffer" aria-label="Permalink to &quot;TransferQueue/ReplayBuffer&quot;">​</a></h3><p>观察 pending/running/finished/failure、storage 容量、poll wait、网络传输和清理。<code>SimpleStorage</code> 是开箱基线，<code>MooncakeStore</code> 在固定提交标为实验性；更换 backend 前先证明 TQ/网络是瓶颈。</p><h3 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h3><p>区分 Parquet 读取、chat template/tokenizer、过长过滤和多机路径。离线可做的重预处理不要每 epoch 重复；但缓存 token 时要绑定 tokenizer/template 版本。</p><h2 id="_6-sync-→-async-不是免费加速" tabindex="-1">6. Sync → async 不是免费加速 <a class="header-anchor" href="#_6-sync-→-async-不是免费加速" aria-label="Permalink to &quot;6. Sync → async 不是免费加速&quot;">​</a></h2>',26)),(t(),l(o,null,{default:e(()=>[r(s,{id:"mermaid-319",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20SYNC%5Bsync%3Cbr%2F%3E%E6%97%B6%E5%BA%8F%E6%B8%85%E6%99%B0%5D%20--%3E%20COL%5Bcolocate_async%3Cbr%2F%3E%E5%85%B1%E7%BD%AE%E6%B5%81%E6%B0%B4%E5%8C%96%5D%0A%20%20%20%20COL%20--%3E%20SEP%5Bseparate_async%3Cbr%2F%3E%E7%8B%AC%E7%AB%8B%E6%89%A9%E7%BC%A9%E5%AE%B9%5D%0A%20%20%20%20SYNC%20-.%20%E5%A2%9E%E5%8A%A0%20.-%3E%20ST%5Bstaleness%20%2F%20buffer%20%2F%20%E7%8A%B6%E6%80%81%E5%A4%8D%E6%9D%82%E5%BA%A6%5D%0A%20%20%20%20COL%20-.%20%E5%A2%9E%E5%8A%A0%20.-%3E%20ST%0A%20%20%20%20SEP%20-.%20%E5%A2%9E%E5%8A%A0%20.-%3E%20ST%0A"})]),fallback:e(()=>[...a[1]||(a[1]=[i(" Loading... ",-1)])]),_:1})),a[4]||(a[4]=n(`<p>只有同步基线正确且阶段等待明确时再进入异步。异步实验额外报告：</p><ul><li>prompt 生成 step 与训练 step 的版本跨度；</li><li>dropped/filtered 轨迹及来源分布；</li><li>ReplayBuffer 容量和反压位置；</li><li>rollout correction/IS weight 分布；</li><li>checkpoint、失败恢复和退出时未消费样本语义。</li></ul><p>吞吐上升但 reward 下降，可能不是超参数偶然波动，而是样本策略分布已改变。</p><h2 id="_7-一次可信-a-b-的写法" tabindex="-1">7. 一次可信 A/B 的写法 <a class="header-anchor" href="#_7-一次可信-a-b-的写法" aria-label="Permalink to &quot;7. 一次可信 A/B 的写法&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hypothesis:</span></span>
<span class="line"><span>  rollout TP=2 限制 replica 数，TP=1 可提高 decode 吞吐</span></span>
<span class="line"><span></span></span>
<span class="line"><span>constants:</span></span>
<span class="line"><span>  commit/config except TP/data slice/seed/GPU/step 10-40</span></span>
<span class="line"><span></span></span>
<span class="line"><span>change:</span></span>
<span class="line"><span>  rollout.tensor_model_parallel_size: 2 -&gt; 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>primary:</span></span>
<span class="line"><span>  valid response tokens/s, median and p95 step time</span></span>
<span class="line"><span></span></span>
<span class="line"><span>guardrails:</span></span>
<span class="line"><span>  reward, response length, KL, OOM, staleness, failed requests</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mechanism evidence:</span></span>
<span class="line"><span>  per-replica decode throughput + selected timeline</span></span>
<span class="line"><span></span></span>
<span class="line"><span>result / decision / rollback:</span></span></code></pre></div><p>若 TP=1 必须同时改变 memory utilization 或 batch 才能运行，诚实地把它写成组合改动，不把收益全归给 TP。</p><h2 id="_8-优化顺序-从不改变语义的改动开始" tabindex="-1">8. 优化顺序：从不改变语义的改动开始 <a class="header-anchor" href="#_8-优化顺序-从不改变语义的改动开始" aria-label="Permalink to &quot;8. 优化顺序：从不改变语义的改动开始&quot;">​</a></h2><p>建议次序：</p><ol><li>修复明显等待/错误配置，固定测量；</li><li>减少 padding、重复预处理和无效传输；</li><li>调 micro batch/token budget/cache/bucket 等执行参数；</li><li>选择更合适的并行与角色放置；</li><li>再考虑异步、过滤、长度/n 等会改变数据分布的联合优化；</li><li>每一步保留单开关回退。</li></ol><p>“语义不变”也需要测试：同一 tiny batch 的 reward、mask、advantage、loss 在容差内一致；同一权重的生成分布在允许范围内一致；分布式 rank 的分子/分母归约一致。</p><h2 id="_9-什么时候值得写自定义优化" tabindex="-1">9. 什么时候值得写自定义优化 <a class="header-anchor" href="#_9-什么时候值得写自定义优化" aria-label="Permalink to &quot;9. 什么时候值得写自定义优化&quot;">​</a></h2><p>只有 profile 证明通用旋钮无法解决，并能明确接口不变量时，才动框架：</p><ul><li>自定义 ReplayBuffer 解决真实的组等待/采样策略；</li><li>新 AgentLoopManager 对接已有高吞吐 agent 平台；</li><li>新 backend adapter 减少当前不必要的权重转换；</li><li>向量化 estimator/reward 时与参考实现做随机等价测试。</li></ul><p>自定义代码的价值不以行数衡量，而以关键路径减少且 guardrail 不退化衡量。</p><h2 id="完成标准" tabindex="-1">完成标准 <a class="header-anchor" href="#完成标准" aria-label="Permalink to &quot;完成标准&quot;">​</a></h2><p>一项可以合并/长期保留的优化，应附：瓶颈证据、假设、最小 diff、正确性/算法不变量、无 profiler 的 A/B、峰值资源、失败回退，以及在哪些模型/长度/拓扑上结论不成立。</p><p>下一步打开<a href="/losh_has_blog/verl-learning/practice/profiling">性能采集</a>，只对已经定位的一个阶段抓 trace。</p>`,17))])}const A=p(h,[["render",u]]);export{P as __pageData,A as default};
